/**
 * Column Registry — the single source of truth for every field the platform
 * understands per entity type.
 *
 * Each entry describes a canonical Prisma field with human-readable metadata,
 * a tier classification (required / recommended / optional), and a curated list
 * of real-world column header aliases that commonly mean the same thing.
 *
 * Usage:
 *   getRegistryForEntity("Product")   -> RegistryField[]
 *   getAllEntityTypes()                -> string[]
 *
 * Adding a new field: append a one-object entry to the relevant entity array.
 *
 * AUTO-GENERATED — do not edit by hand.
 * Re-generate with: node scripts/gen-column-registry.js
 */

export interface RegistryField {
  /** Exact Prisma field name — must match the schema exactly. */
  canonicalKey: string;
  /** Human-readable label shown in the mapping UI. */
  displayLabel: string;
  /** One sentence explaining what this field means. */
  description: string;
  /**
   * - required     -> import cannot produce useful data without this
   * - recommended  -> needed for AI capabilities to unlock
   * - optional     -> enriches the model but not blocking
   */
  tier: "required" | "recommended" | "optional";
  dataType: "string" | "number" | "date" | "boolean";
  /** Normalised (lowercase, no spaces/punctuation) column header aliases. */
  aliases: string[];
  /** Representative example value shown in the UI. */
  example?: string;
  /** AI capability label that this field unlocks — shown as amber hint in UI. */
  unlocksCapability?: string;
}

export interface ColumnDefinition {
  canonicalName: string;       // exact column name from schema (snake_case)
  entityName: string;          // table name e.g. "purchase_order_line"
  domain: string;              // domain name e.g. "Procurement"
  displayName: string;         // human-readable e.g. "Unit Price"
  dataType: string;            // from schema e.g. "DECIMAL(12,4)"
  isRequired: boolean;         // nullable: false
  isPrimaryKey: boolean;
  isForeignKey: boolean;
  foreignKeyTarget?: string;   // e.g. "product.sku"
  description?: string;        // from note field
  aliases: string[];           // common alternative names
}

