// ─── Lookup Maps ────────────────────────────────────────────────────────────────

export const REGISTRY_BY_ENTITY: Record<string, ColumnDefinition[]> = {};
for (const col of CANONICAL_COLUMN_REGISTRY) {
  if (!REGISTRY_BY_ENTITY[col.entityName]) {
    REGISTRY_BY_ENTITY[col.entityName] = [];
  }
  REGISTRY_BY_ENTITY[col.entityName].push(col);
}

const ENTITY_PRIORITY_ORDER: string[] = [
  'inventory_balance',
  'product',
  'purchase_order_line',
  'purchase_order',
  'sales_order_line',
  'sales_order',
  'work_order',
  'bom_line',
  'bom_header',
];

function entityPriority(entityName: string): number {
  const idx = ENTITY_PRIORITY_ORDER.indexOf(entityName);
  return idx === -1 ? ENTITY_PRIORITY_ORDER.length : idx;
}

export const REGISTRY_BY_ALIAS: Record<string, ColumnDefinition> = {};
for (const col of CANONICAL_COLUMN_REGISTRY) {
  for (const alias of col.aliases) {
    const existing = REGISTRY_BY_ALIAS[alias];
    if (!existing || entityPriority(col.entityName) < entityPriority(existing.entityName)) {
      REGISTRY_BY_ALIAS[alias] = col;
    }
  }
}

// ─── Exports ──────────────────────────────────────────────────────────────────

/**
 * Returns the registry fields for a given entity type.
 * Returns an empty array if the entity type is not registered.
 */
export function getRegistryForEntity(entityType: string): RegistryField[] {
  // Check the legacy PascalCase REGISTRY first
  if (REGISTRY[entityType] && REGISTRY[entityType].length > 0) {
    return REGISTRY[entityType];
  }
  // Fall back to REGISTRY_BY_ENTITY (canonical column definitions → RegistryField shape)
  // This covers new entity types that only exist in the canonical schema.
  // Try PascalCase key first, then convert to snake_case for lookup.
  const snakeCase = entityType.replace(/([A-Z])/g, '_$1').toLowerCase().replace(/^_/, '');
  const canonical = REGISTRY_BY_ENTITY[entityType] ?? REGISTRY_BY_ENTITY[snakeCase] ?? [];
  if (canonical.length > 0) {
    return canonical.map((c): RegistryField => ({
      canonicalKey: c.canonicalName,
      displayLabel: c.displayName,
      description: c.description ?? `${c.displayName} field from ${c.entityName}`,
      tier: c.isPrimaryKey || c.isRequired ? "required" : "optional",
      dataType: c.dataType.startsWith("DECIMAL") || c.dataType === "INTEGER" || c.dataType === "BIGINT" ? "number"
        : c.dataType === "DATE" || c.dataType === "TIMESTAMP" ? "date"
        : c.dataType === "BOOLEAN" ? "boolean"
        : "string",
      aliases: c.aliases,
    }));
  }
  return [];
}

/**
 * Returns all registered entity type names.
 * Includes both legacy REGISTRY keys and canonical REGISTRY_BY_ENTITY keys.
 */
export function getAllEntityTypes(): string[] {
  const legacy = Object.keys(REGISTRY);
  const canonical = Object.keys(REGISTRY_BY_ENTITY);
  return [...new Set([...legacy, ...canonical])];
}
